#include <bits/stdc++.h>
using namespace std;

const int N=1e4+4;

struct Node{
    int p,d;
}a[N];

bool cmp(Node x,Node y){
    return x.d<y.d;
}

int n;

int main(){
    while(cin>>n){
        for(int i=1;i<=n;i++)
            cin>>a[i].p>>a[i].d;
        priority_queue<int> q;
        sort(a+1,a+n+1,cmp);
        for(int i=1;i<=n;i++){
            if(q.size()<a[i].d)
                q.push(-a[i].p);
            else if(-q.top()<a[i].p)
                q.pop(),q.push(-a[i].p);
        }
        int ans=0;
        while(!q.empty())
            ans+=-q.top(),q.pop();
        cout<<ans<<'\n';
    }
    return 0;
}
